### Display Connection Status Indicator in React

Source: https://github.com/supabase/supabase/blob/master/apps/docs/content/troubleshooting/realtime-heartbeat-messages.mdx

Monitor Supabase realtime heartbeat status and display connection health to users. Listens to heartbeat events to track connection states: 'ok' (healthy), 'timeout' (poor), and 'disconnected'. Updates UI component state based on received heartbeat status.

```tsx
import { useState, useEffect } from 'react'
import { createClient } from '@supabase/supabase-js'

function ConnectionIndicator() {
  const supabase = createClient(SUPABASE_URL, SUPABASE_KEY)
  const [status, setStatus] = useState('healthy')

  useEffect(() => {
    supabase.realtime.onHeartbeat((heartbeatStatus) => {
      if (heartbeatStatus === 'ok') {
        setStatus('healthy')
      } else if (heartbeatStatus === 'timeout') {
        setStatus('poor')
      } else if (heartbeatStatus === 'disconnected') {
        setStatus('disconnected')
      }
    })
  }, [supabase])

  return (
    <div>
      <span>Connection: {status}</span>
    </div>
  )
}
```

